{
  "decisions": [
    {
      "id": "D1",
      "content": "プロジェクト・アオゾラを本日付で正式キックオフし、正式発足とする。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D2",
      "content": "週次定例は毎週水曜日10時から1時間枠で開催し、各部署から少なくとも1名参加する運用とする。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D3",
      "content": "第1フェーズではトランザクション系データを移行せず、マスタ系データを先行移行し、過去の入出庫履歴は旧システムを参照用に残して対応する。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D4",
      "content": "共通基盤の認証・マスタ配信は、サクラ商事さんとの共同利用の第3案で進める。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D5",
      "content": "障害発生時の一次受け窓口は情報システム部ではなくQAチームが担う。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D6",
      "content": "移行方式は全拠点一括や並行稼働ではなく、拠点を分けて順番に切り替える段階移行で確定する。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D7",
      "content": "本番リリース目標は9月末から2026年10月15日に変更する。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D8",
      "content": "切替作業は土曜深夜帯を前提として進める。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D9",
      "content": "新システムのユーザー権限は今回は既存のロール定義を流用し、新規設計は行わない。",
      "decided_by": "芦田 巧"
    }
  ],
